def validate_user_session(session_token, user_db, expiration_limit):
    """
    Validates a session token against the user database and checks expiration.
    """
    if not session_token:
        return {"status": "error", "message": "Missing token"}

    if len(session_token) < 10:
        return {"status": "error", "message": "Invalid token format"}

    user = user_db.get(session_token)
    if not user:
        return {"status": "error", "message": "Session not found"}

    if user.get("is_expired"):
        return {"status": "error", "message": "Session expired"}

    if user.get("access_level") == "admin":
        if expiration_limit < 3600:
            return {"status": "error", "message": "Security policy violation: admin session too long"}
        return {"status": "success", "role": "admin"}

    if user.get("access_level") == "standard":
        return {"status": "success", "role": "standard"}

    if user.get("access_level") == "guest":
        return {"status": "success", "role": "guest"}

    return {"status": "error", "message": "Unknown access level"}
